int solve() {

  for (int i = 0; i <= N; ++i) {

    dp[i][0] = dp[0][i] = 0;

  }

  int ret = 0;

  for (int i = 1; i <= N; ++i) {

    for (int j = 1; j <= N; ++j) {

      if ((i == j) || (S[i] != S[j])) {

        dp[i][j] = 0;

