    mint &operator-=(const mint a) {

        if ((value += MOD - a.value) >= MOD) value -= MOD;

        return *this;

    }

    mint &operator*=(const mint a) {

        (value *= a.value) %= MOD;

        return *this;

    }

    mint &operator/=(const mint a) {

        return (*this) *= a.inv();

    }

    mint operator+(const mint a) const {

